import{_ as a,o as e,c as l,ag as r}from"./chunks/framework.DEs8X8sU.js";const p=JSON.parse('{"title":"プラン・コース管理","description":"","frontmatter":{"title":"プラン・コース管理"},"headers":[],"relativePath":"tenant/10-plans.md","filePath":"tenant/10-plans.md"}'),i={name:"tenant/10-plans.md"};function d(n,t,o,h,s,_){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="_10-プラン・コース管理" tabindex="-1">10. プラン・コース管理 <a class="header-anchor" href="#_10-プラン・コース管理" aria-label="Permalink to &quot;10. プラン・コース管理&quot;">​</a></h1><p>プラン・コース管理では、食べ放題、飲み放題、セットコース、予約コースなどを設定します。</p><h2 id="時間制プラン" tabindex="-1">時間制プラン <a class="header-anchor" href="#時間制プラン" aria-label="Permalink to &quot;時間制プラン&quot;">​</a></h2><p>食べ放題や飲み放題など、利用時間とラストオーダーが決まっているメニューに利用します。</p><ol><li>プラン名を入力します。</li><li>利用時間、ラストオーダー、価格を設定します。</li><li>対象商品または対象カテゴリを設定します。</li><li>テスト注文で時間表示と会計金額を確認します。</li></ol><h2 id="コース料理" tabindex="-1">コース料理 <a class="header-anchor" href="#コース料理" aria-label="Permalink to &quot;コース料理&quot;">​</a></h2><p>コース料理では、提供順や構成品目を管理します。予約管理と組み合わせる場合は、予約時に選べるコース内容も確認してください。</p><h2 id="運用時の注意" tabindex="-1">運用時の注意 <a class="header-anchor" href="#運用時の注意" aria-label="Permalink to &quot;運用時の注意&quot;">​</a></h2><ul><li>プラン料金と単品料金の二重計上がないか確認してください。</li><li>ラストオーダー時刻はスタッフ全員に共有してください。</li><li>対象外の商品が注文できないかテストしてください。</li><li>キャンペーン価格を設定する場合は、終了後に戻す運用を決めてください。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>プランが表示されない</td><td>販売状態、対象店舗、表示期間を確認してください。</td></tr><tr><td>金額が違う</td><td>プラン価格、オプション、割引を確認してください。</td></tr><tr><td>ラストオーダー後に注文できる</td><td>プラン時間と端末時刻を確認してください。</td></tr><tr><td>コース内容が違う</td><td>コース構成とメニュー登録を確認してください。</td></tr></tbody></table>',11)])])}const u=a(i,[["render",d]]);export{p as __pageData,u as default};
